6803 /// Integer compare with boolean values can always be turned into bitwise ops.
6804 static Instruction *canonicalizeICmpBool(ICmpInst &I,
6805                                          InstCombiner::BuilderTy &Builder) {
6806   Value *A = I.getOperand(0), *B = I.getOperand(1);
6807   assert(A->getType()->isIntOrIntVectorTy(1) && "Bools only");
6808 
6809   // A boolean compared to true/false can be simplified to Op0/true/false in
6810   // 14 out of the 20 (10 predicates * 2 constants) possible combinations.
6811   // Cases not handled by InstSimplify are always 'not' of Op0.
6812   if (match(B, m_Zero())) {
6813     switch (I.getPredicate()) {
6814       case CmpInst::ICMP_EQ:  // A ==   0 -> !A
6815       case CmpInst::ICMP_ULE: // A <=u  0 -> !A
6816       case CmpInst::ICMP_SGE: // A >=s  0 -> !A
6817         return BinaryOperator::CreateNot(A);
6818       default:
6819         llvm_unreachable("ICmp i1 X, C not simplified as expected.");
6820     }
6821   } else if (match(B, m_One())) {
6822     switch (I.getPredicate()) {
6823       case CmpInst::ICMP_NE:  // A !=  1 -> !A
6824       case CmpInst::ICMP_ULT: // A <u  1 -> !A
6825       case CmpInst::ICMP_SGT: // A >s -1 -> !A
6826         return BinaryOperator::CreateNot(A);
6827       default:
6828         llvm_unreachable("ICmp i1 X, C not simplified as expected.");
6829     }
6830   }
6831 
6832   switch (I.getPredicate()) {
6833   default:
6834     llvm_unreachable("Invalid icmp instruction!");
6835   case ICmpInst::ICMP_EQ:
6836     // icmp eq i1 A, B -> ~(A ^ B)
6837     return BinaryOperator::CreateNot(Builder.CreateXor(A, B));
6838 
6839   case ICmpInst::ICMP_NE:
6840     // icmp ne i1 A, B -> A ^ B
6841     return BinaryOperator::CreateXor(A, B);
6842 
6843   case ICmpInst::ICMP_UGT:
6844     // icmp ugt -> icmp ult
6845     std::swap(A, B);
6846     [[fallthrough]];
6847   case ICmpInst::ICMP_ULT:
6848     // icmp ult i1 A, B -> ~A & B
6849     return BinaryOperator::CreateAnd(Builder.CreateNot(A), B);
6850 
6851   case ICmpInst::ICMP_SGT:
6852     // icmp sgt -> icmp slt
6853     std::swap(A, B);
